import React, { useState, useContext } from 'react';
import { taxasIRT } from '../data/mockData';
import { AppContext } from '../App';
import { Colaborador } from '../types';

const Processamento: React.FC = () => {
  const { empresa, colaboradores } = useContext(AppContext);
  const ativos = colaboradores.filter(c => c.status === 'Ativo');

  const currentYear = new Date().getFullYear();
  const currentDay = new Date().getDate();
  const [selectedMonth, setSelectedMonth] = useState('Janeiro');
  const [selectedYear, setSelectedYear] = useState(currentYear.toString());
  const [selectedDay, setSelectedDay] = useState(currentDay.toString());

  const [showFormModal, setShowFormModal] = useState(false);
  const [showReceiptModal, setShowReceiptModal] = useState(false);
  const [selectedColab, setSelectedColab] = useState<Colaborador | null>(null);

  // Form states
  const [formSalario, setFormSalario] = useState(0);
  const [formFaltas, setFormFaltas] = useState(0);
  const [formAlimentacao, setFormAlimentacao] = useState(0);
  const [formTransporte, setFormTransporte] = useState(0);
  const [formFerias, setFormFerias] = useState(0);
  const [outrosSubsidios, setOutrosSubsidios] = useState<{nome: string, valor: number}[]>([]);
  const [tempSubsidioNome, setTempSubsidioNome] = useState('');
  const [tempSubsidioValor, setTempSubsidioValor] = useState(0);
  const [formHorasExtra, setFormHorasExtra] = useState(0);
  const [formBonus, setFormBonus] = useState(0);

  const calcularIRT = (baseSujeitaIRT: number) => {
    const escalao = taxasIRT.find(t => baseSujeitaIRT >= t.minimo && baseSujeitaIRT <= t.maximo);
    if (!escalao) return 0;
    const calc = ((baseSujeitaIRT - escalao.minimo) * (escalao.taxa / 100)) + escalao.parcelaAbt;
    return calc > 0 ? calc : 0;
  };

  const handleStartProcessar = (colab: Colaborador) => {
    setSelectedColab(colab);
    setFormSalario(colab.salarioBase || 0);
    setFormFaltas(0);
    setFormAlimentacao(30000);
    setFormTransporte(20000);
    setFormFerias(0);
    setOutrosSubsidios([]);
    setFormHorasExtra(0);
    setFormBonus(0);
    setShowFormModal(true);
  };

  const addOutroSubsidio = () => {
    if (tempSubsidioNome && tempSubsidioValor > 0) {
      setOutrosSubsidios([...outrosSubsidios, { nome: tempSubsidioNome, valor: tempSubsidioValor }]);
      setTempSubsidioNome('');
      setTempSubsidioValor(0);
    }
  };

  const removeOutroSubsidio = (index: number) => {
    setOutrosSubsidios(outrosSubsidios.filter((_, i) => i !== index));
  };

  const handleConfirmForm = (e: React.FormEvent) => {
    e.preventDefault();
    setShowFormModal(false);
    setShowReceiptModal(true);
  };

  const currentCalc = () => {
    const totalOutros = outrosSubsidios.reduce((acc, curr) => acc + curr.valor, 0);
    const totalBruto = formSalario + formAlimentacao + formTransporte + formFerias + totalOutros + formHorasExtra + formBonus;
    const baseSalarioLiquidoFaltas = formSalario - formFaltas;

    const taxaINSS = empresa?.taxaINSS || 3;
    const valorINSS = baseSalarioLiquidoFaltas * (taxaINSS / 100);
    const baseIRT = baseSalarioLiquidoFaltas - valorINSS + formAlimentacao + formTransporte + formFerias + totalOutros + formHorasExtra + formBonus; 
    const valorIRT = calcularIRT(baseIRT);

    const totalDescontos = valorINSS + valorIRT + formFaltas;
    const salarioLiquido = totalBruto - totalDescontos;

    return { totalBruto, valorINSS, valorIRT, totalDescontos, salarioLiquido };
  };

  const handleImprimir = () => {
    window.print();
  };

  const handleGuardar = () => {
    const element = document.getElementById('recibo-para-impressao');
    if (!element) return;

    // @ts-ignore
    const opt = {
      margin: 10,
      filename: `Recibo_${selectedColab?.nome.replace(/ /g, '_')}_${selectedMonth}.pdf`,
      image: { type: 'jpeg', quality: 0.98 },
      html2canvas: { scale: 2 },
      jsPDF: { unit: 'mm', format: 'a4', orientation: 'portrait' }
    };

    // @ts-ignore
    window.html2pdf().from(element).set(opt).save();
  };

  return (
    <div className="p-8">
      <div className="flex items-center justify-between mb-8">
        <div>
          <h2 className="text-2xl font-black tracking-tight">Processamento de Salários</h2>
          <p className="text-slate-500">Gere a folha de pagamento do período selecionado.</p>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-4 gap-6 mb-8">
        <div className="bg-white dark:bg-slate-900 p-6 rounded-xl border border-slate-200 dark:border-slate-800">
          <label className="block text-sm font-medium text-slate-500 mb-2">Mês</label>
          <select value={selectedMonth} onChange={e => setSelectedMonth(e.target.value)} className="w-full bg-slate-50 dark:bg-slate-800 border-none rounded-lg focus:ring-primary p-2">
            {['Janeiro', 'Fevereiro', 'Março', 'Abril', 'Maio', 'Junho', 'Julho', 'Agosto', 'Setembro', 'Outubro', 'Novembro', 'Dezembro'].map(m => (
              <option key={m} value={m}>{m}</option>
            ))}
          </select>
        </div>
        <div className="bg-white dark:bg-slate-900 p-6 rounded-xl border border-slate-200 dark:border-slate-800">
          <label className="block text-sm font-medium text-slate-500 mb-2">Ano</label>
          <select value={selectedYear} onChange={e => setSelectedYear(e.target.value)} className="w-full bg-slate-50 dark:bg-slate-800 border-none rounded-lg focus:ring-primary p-2">
            {['2024', '2025', '2026', '2027'].map(y => (
              <option key={y} value={y}>{y}</option>
            ))}
          </select>
        </div>
        <div className="bg-white dark:bg-slate-900 p-6 rounded-xl border border-slate-200 dark:border-slate-800">
          <label className="block text-sm font-medium text-slate-500 mb-2">Dia</label>
          <input type="number" min="1" max="31" value={selectedDay} onChange={e => setSelectedDay(e.target.value)} className="w-full bg-slate-50 dark:bg-slate-800 border-none rounded-lg focus:ring-primary p-2" />
        </div>
        <div className="bg-white dark:bg-slate-900 p-6 rounded-xl border border-slate-200 dark:border-slate-800 flex items-center justify-between">
          <div>
            <p className="text-xs text-slate-500 uppercase font-bold text-[10px]">Status</p>
            <p className="text-sm font-medium text-emerald-500">Manual</p>
          </div>
          <span className="material-symbols-outlined text-slate-300">event_available</span>
        </div>
      </div>

      <div className="bg-white dark:bg-slate-900 rounded-xl border border-slate-200 dark:border-slate-800 overflow-hidden shadow-sm">
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead className="bg-slate-50 dark:bg-slate-800/50 border-b border-slate-200 dark:border-slate-800">
              <tr>
                <th className="p-4 text-xs font-bold text-slate-500 uppercase">Colaborador</th>
                <th className="p-4 text-xs font-bold text-slate-500 uppercase text-right">Salário Base</th>
                <th className="p-4 text-xs font-bold text-slate-500 uppercase text-center">Ação</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100 dark:divide-slate-800">
              {ativos.map(c => (
                <tr key={c.id} className="hover:bg-slate-50 dark:hover:bg-slate-800/50 transition-colors">
                  <td className="p-4">
                    <div className="flex items-center gap-3">
                      <div className="size-10 rounded-full bg-primary/10 flex items-center justify-center text-primary font-bold text-xs uppercase">{c.nome.substring(0, 2)}</div>
                      <div>
                        <p className="text-sm font-semibold">{c.nome}</p>
                        <p className="text-xs text-slate-500">{c.cargo}</p>
                      </div>
                    </div>
                  </td>
                  <td className="p-4 text-right font-medium text-sm">{c.salarioBase.toLocaleString()} Kz</td>
                  <td className="p-4 text-center">
                    <button onClick={() => handleStartProcessar(c)} className="text-primary border border-primary/20 hover:bg-primary/10 px-4 py-1.5 rounded-lg text-xs font-bold transition-colors">Processar</button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {showFormModal && selectedColab && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-[60] p-4 backdrop-blur-sm">
          <div className="bg-white dark:bg-slate-900 rounded-xl max-w-lg w-full max-h-[90vh] overflow-y-auto shadow-2xl">
            <div className="p-6 border-b border-slate-200 dark:border-slate-800 flex items-start justify-between">
              <div>
                <h2 className="font-black text-xl text-slate-900 dark:text-white uppercase tracking-wider">Processamento</h2>
                <div className="text-slate-500 text-sm">{selectedColab.nome}</div>
              </div>
              <button onClick={() => setShowFormModal(false)} className="p-2 hover:bg-slate-100 rounded-lg"><span className="material-symbols-outlined">close</span></button>
            </div>
            <form onSubmit={handleConfirmForm} className="p-6 space-y-4">
              <div className="space-y-1.5">
                <label className="text-sm font-semibold text-slate-700">Salário Base (Kz)</label>
                <input required type="text" value={formSalario ? formSalario.toLocaleString('pt-AO') : ''} onChange={e => setFormSalario(Number(e.target.value.replace(/\D/g, '')))} className="w-full px-3 py-2 bg-slate-50 border border-slate-200 rounded-lg font-bold text-primary" />
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1.5"><label className="text-sm font-semibold text-slate-700">Alimentação</label><input type="number" value={formAlimentacao === 0 ? '' : formAlimentacao} onChange={e => setFormAlimentacao(Number(e.target.value))} className="w-full px-3 py-2 bg-slate-50 border border-slate-200 rounded-lg" /></div>
                <div className="space-y-1.5"><label className="text-sm font-semibold text-slate-700">Transporte</label><input type="number" value={formTransporte === 0 ? '' : formTransporte} onChange={e => setFormTransporte(Number(e.target.value))} className="w-full px-3 py-2 bg-slate-50 border border-slate-200 rounded-lg" /></div>
              </div>

              <div className="p-4 bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-xl space-y-3">
                <label className="text-sm font-bold text-slate-800 dark:text-slate-200 flex items-center gap-2">Outros Subsídios</label>
                <div className="flex gap-2">
                  <input type="text" placeholder="Nome" value={tempSubsidioNome} onChange={e => setTempSubsidioNome(e.target.value)} className="flex-1 px-3 py-1.5 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-lg text-sm" />
                  <input type="number" placeholder="Valor" value={tempSubsidioValor || ''} onChange={e => setTempSubsidioValor(Number(e.target.value))} className="w-24 px-3 py-1.5 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-lg text-sm" />
                  <button type="button" onClick={addOutroSubsidio} className="px-3 py-1.5 bg-primary text-white rounded-lg text-xs font-bold">Add</button>
                </div>
                {outrosSubsidios.map((s, idx) => (
                  <div key={idx} className="flex items-center justify-between text-xs bg-white dark:bg-slate-900 p-2 rounded-lg border border-slate-100 dark:border-slate-800">
                    <span>{s.nome}</span>
                    <div className="flex items-center gap-2">
                      <span className="font-bold">{s.valor.toLocaleString()} Kz</span>
                      <button type="button" onClick={() => removeOutroSubsidio(idx)} className="text-red-500"><span className="material-symbols-outlined text-sm">delete</span></button>
                    </div>
                  </div>
                ))}
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1.5"><label className="text-sm font-semibold text-green-700">Horas Extra</label><input type="number" value={formHorasExtra === 0 ? '' : formHorasExtra} onChange={e => setFormHorasExtra(Number(e.target.value))} className="w-full px-3 py-2 bg-green-50 border border-green-200 rounded-lg" /></div>
                <div className="space-y-1.5"><label className="text-sm font-semibold text-green-700">Bónus</label><input type="number" value={formBonus === 0 ? '' : formBonus} onChange={e => setFormBonus(Number(e.target.value))} className="w-full px-3 py-2 bg-green-50 border border-green-200 rounded-lg" /></div>
              </div>

              <div className="space-y-1.5 border-t pt-4">
                <label className="text-sm font-semibold text-red-600">Faltas (Desconto)</label>
                <input type="number" value={formFaltas === 0 ? '' : formFaltas} onChange={e => setFormFaltas(Number(e.target.value))} className="w-full px-3 py-2 bg-red-50 border border-red-200 rounded-lg" />
              </div>

              <button type="submit" className="w-full mt-4 py-3 bg-primary text-white rounded-lg font-bold hover:bg-primary/90 flex items-center justify-center gap-2">
                <span className="material-symbols-outlined">payments</span>
                Processar
              </button>
            </form>
          </div>
        </div>
      )}

      {showReceiptModal && selectedColab && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4 backdrop-blur-sm">
          <div className="bg-white rounded-xl max-w-[210mm] w-full max-h-[95vh] overflow-y-auto shadow-2xl">
            <style>{`
              @media print {
                body * { visibility: hidden; }
                #recibo-para-impressao, #recibo-para-impressao * { visibility: visible; }
                #recibo-para-impressao { position: absolute; left: 0; top: 0; width: 210mm; padding: 15mm; }
                .no-print { display: none !important; }
              }
            `}</style>
            <div className="p-12 bg-white text-slate-900" id="recibo-para-impressao" style={{ minHeight: '297mm', boxSizing: 'border-box' }}>
              <div className="flex justify-between items-start border-b-4 border-primary pb-6 mb-8">
                <div className="flex gap-4 items-center">
                  <img src="/logo.png" alt="Logo" className="w-20 h-20 object-contain" />
                  <div>
                    <h1 className="text-2xl font-black text-primary uppercase">{empresa?.nome || 'EMPRESA'}</h1>
                    <p className="text-xs text-slate-500">NIF: {empresa?.nif || '-'}</p>
                    <p className="text-[10px] text-slate-500 max-w-[250px]">{empresa?.endereco || ''}</p>
                  </div>
                </div>
                <div className="text-right">
                  <h2 className="text-lg font-black text-slate-800">RECIBO DE SALÁRIO</h2>
                  <div className="mt-2 bg-slate-50 border p-3 rounded-lg text-right">
                    <p className="text-sm font-bold">Período: {selectedMonth} / {selectedYear}</p>
                    <p className="text-[10px] text-slate-400">Data: {selectedDay}/{selectedMonth}</p>
                  </div>
                </div>
              </div>

              <div className="grid grid-cols-2 gap-8 mb-8 bg-slate-50/50 border p-6 rounded-xl">
                <div>
                  <h3 className="text-[10px] font-black text-primary border-b border-primary/20 mb-3 uppercase">Funcionário</h3>
                  <p className="text-sm font-bold">{selectedColab.nome}</p>
                  <p className="text-xs text-slate-600 mt-1">ID: {selectedColab.numeroColaborador || '-'}</p>
                  <p className="text-xs text-slate-600">Cargo: {selectedColab.cargo}</p>
                  <p className="text-xs text-slate-600">Contrato: {selectedColab.tipoContrato || '-'}</p>
                </div>
                <div>
                  <h3 className="text-[10px] font-black text-primary border-b border-primary/20 mb-3 uppercase">Pagamento e Fiscal</h3>
                  <p className="text-xs"><strong>NIF:</strong> {selectedColab.nif}</p>
                  <p className="text-xs"><strong>INSS:</strong> {selectedColab.inss || '-'}</p>
                  <p className="text-xs font-bold mt-2 py-1.5 px-3 bg-primary/10 text-primary rounded inline-block w-full">IBAN: {selectedColab.iban || '-'}</p>
                </div>
              </div>

              <table className="w-full mb-8">
                <thead>
                  <tr className="bg-primary text-white text-[10px] font-black uppercase">
                    <th className="p-3 text-left rounded-tl-lg">Descrição</th>
                    <th className="p-3 text-right rounded-tr-lg">Valor (Kz)</th>
                  </tr>
                </thead>
                <tbody className="border-x border-b border-slate-100 text-xs">
                  <tr className="border-b border-slate-50"><td className="p-3">Salário Base</td><td className="p-3 text-right">{formSalario.toLocaleString('pt-AO', { minimumFractionDigits: 2 })}</td></tr>
                  {formAlimentacao > 0 && <tr className="border-b border-slate-50"><td className="p-3">Subsídio Alimentação</td><td className="p-3 text-right">{formAlimentacao.toLocaleString('pt-AO', { minimumFractionDigits: 2 })}</td></tr>}
                  {formTransporte > 0 && <tr className="border-b border-slate-50"><td className="p-3">Subsídio Transporte</td><td className="p-3 text-right">{formTransporte.toLocaleString('pt-AO', { minimumFractionDigits: 2 })}</td></tr>}
                  {formFerias > 0 && <tr className="border-b border-slate-50"><td className="p-3">Subsídio Férias</td><td className="p-3 text-right">{formFerias.toLocaleString('pt-AO', { minimumFractionDigits: 2 })}</td></tr>}
                  {outrosSubsidios.map((s, idx) => (
                    <tr key={idx} className="border-b border-slate-50"><td className="p-3">{s.nome}</td><td className="p-3 text-right">{s.valor.toLocaleString('pt-AO', { minimumFractionDigits: 2 })}</td></tr>
                  ))}
                  {formHorasExtra > 0 && <tr className="border-b border-slate-50"><td className="p-3">Horas Extra</td><td className="p-3 text-right">{formHorasExtra.toLocaleString('pt-AO', { minimumFractionDigits: 2 })}</td></tr>}
                  {formBonus > 0 && <tr className="border-b border-slate-50"><td className="p-3">Bónus / Prémio</td><td className="p-3 text-right">{formBonus.toLocaleString('pt-AO', { minimumFractionDigits: 2 })}</td></tr>}

                  <tr className="bg-slate-50 font-black"><td className="p-3">TOTAL BRUTO</td><td className="p-3 text-right">{currentCalc().totalBruto.toLocaleString('pt-AO', { minimumFractionDigits: 2 })}</td></tr>

                  <tr><td colSpan={2} className="px-3 pt-6 pb-2 text-[10px] font-black text-slate-400 uppercase">Deduções</td></tr>
                  <tr className="border-b border-slate-50"><td className="p-3">Segurança Social ({empresa?.taxaINSS || 3}%)</td><td className="p-3 text-right text-red-500">- {currentCalc().valorINSS.toLocaleString('pt-AO', { minimumFractionDigits: 2 })}</td></tr>
                  <tr className="border-b border-slate-50"><td className="p-3">IRT (Imposto)</td><td className="p-3 text-right text-red-500">- {currentCalc().valorIRT.toLocaleString('pt-AO', { minimumFractionDigits: 2 })}</td></tr>
                  {formFaltas > 0 && <tr className="border-b border-slate-50"><td className="p-3">Faltas</td><td className="p-3 text-right text-red-500">- {formFaltas.toLocaleString('pt-AO', { minimumFractionDigits: 2 })}</td></tr>}
                </tbody>
              </table>

              <div className="bg-primary p-6 rounded-xl text-white flex justify-between items-center mb-12">
                <span className="text-sm font-bold uppercase tracking-widest">Valor Líquido</span>
                <span className="text-3xl font-black">{currentCalc().salarioLiquido.toLocaleString('pt-AO', { minimumFractionDigits: 2 })} Kz</span>
              </div>

              <div className="grid grid-cols-2 gap-12 mt-12 text-center">
                <div><div className="border-b-2 border-slate-900 h-12 mb-2"></div><p className="text-[10px] font-black uppercase">Pela Entidade Empregadora</p></div>
                <div><div className="border-b-2 border-slate-900 h-12 mb-2"></div><p className="text-[10px] font-black uppercase">O Funcionário</p></div>
              </div>
            </div>

            <div className="p-6 bg-slate-100 flex gap-4 no-print">
              <button onClick={handleGuardar} className="flex-1 py-3 bg-primary text-white rounded-lg font-bold flex items-center justify-center gap-2"><span className="material-symbols-outlined">save_alt</span> GUARDAR PDF</button>
              <button onClick={handleImprimir} className="flex-1 py-3 bg-white text-slate-900 border border-slate-300 rounded-lg font-bold flex items-center justify-center gap-2"><span className="material-symbols-outlined">print</span> IMPRIMIR</button>
              <button onClick={() => setShowReceiptModal(false)} className="px-8 py-3 bg-slate-200 text-slate-600 rounded-lg font-bold">FECHAR</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Processamento;
